// Central UI string registry. Components import from here so a single
// diff updates voice across the site.
export const COPY = {
  brand: "Michael Quintin",
  // R04: paletteHint and helpHint kept as exports for any inline page
  // hints that still want them; the bottom status bar that originally
  // displayed them is gone.
  paletteHint: "⌘K palette",
  helpHint: "F1 help",
  paletteOpen: "command or search — ESC to close",
  paletteFooter: "↑↓ navigate   ↵ run   ⌘↵ run in new tab   /  filter   ?  help",
  sessionInit: "session initialized · ⌘K to search",
  sessionResumed: "session resumed",
  classification: {
    public: "UNCLASSIFIED",
    restricted: "CONTROLLED UNCLASSIFIED",
    private: "CONFIDENTIAL · DO NOT REDISTRIBUTE",
  },
  errors: {
    notFound: "404. no file at this path. ⌘K to navigate.",
    runtime: (m: string) => `! process crashed. error: ${m}. ⌘K to navigate.`,
    clipboardDenied: "! clipboard permission denied",
  },
  toast: {
    copied: "✓ copied",
    downloadStarted: "· download started",
  },
  resume: {
    download: "Download PDF",
    print: "Print",
    copy: "Copy to clipboard",
    references: "Available on request.",
  },
  projects: {
    headerPrefix: ">> projects",
    emptyFilter: "no projects matched filter. / to edit.",
    rowOpen: "↵ open",
    rowOpenTab: "⌘↵ tab",
  },
  // R04: ticker removed with the status bar.
} as const;

// Words and phrases that must not appear in chrome, button text, or
// marketing copy. The list mirrors the "What to avoid" section of
// docs/voice-guide.md. Long-form prose authored by Michael is exempt;
// the lint script excludes MDX bodies. A per-occurrence override is
// available via a /* voice-allow */ comment immediately preceding the
// offending string.
export const FORBIDDEN_WORDS = [
  // Corporate-speak
  "synergy",
  "ecosystem",
  "leverage", // verb sense; nouns covered by override comment
  "unlock",
  "unleash",
  "robust",
  "innovative",
  "thought-leader",
  "thought leader",
  "visionary",
  "disrupt",
  "disruption",
  "revolutionary",
  "game-changing",
  "game changing",
  "cutting-edge",
  "cutting edge",
  "seamless",
  "effortless",
  "empowering",
  "passionate",
  // Intensifier abuse
  "literally",
  // Hedges that erase the claim
  "perhaps maybe",
  "maybe possibly",
  "perhaps maybe possibly",
  "might potentially",
] as const;

export type ForbiddenWord = (typeof FORBIDDEN_WORDS)[number];

