1	"use client";
2	
3	import {
4	  useEffect,
5	  useRef,
6	  type ChangeEvent,
7	  type FormEvent,
8	  type KeyboardEvent,
9	} from "react";
10	import Button from "@/components/primitives/Button";
11	import Cluster from "@/components/primitives/Cluster";
12	
13	const MAX_LEN = 4000;
14	const MAX_ROWS = 6;
15	
16	type ChatInputProps = {
17	  value: string;
18	  onChange: (next: string) => void;
19	  onSubmit: () => void;
20	  onStop?: () => void;
21	  isStreaming: boolean;
22	  /**
23	   * Optional handler invoked when the global focus-input shortcut fires
24	   * (Cmd/Ctrl+K or "/" outside an editable element). The default behavior
25	   * focuses the textarea and scrolls the viewport to the bottom.
26	   */
27	  onFocusShortcut?: () => void;
28	};
29	
30	export default function ChatInput({
31	  value,
32	  onChange,
33	  onSubmit,
34	  onStop,
35	  isStreaming,
36	  onFocusShortcut,
37	}: ChatInputProps) {
38	  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
39	  const charCount = value.length;
40	  const trimmed = value.trim();
41	  const canSubmit = !isStreaming && trimmed.length > 0 && charCount <= MAX_LEN;
42	  const isStreamingRef = useRef(isStreaming);
43	  isStreamingRef.current = isStreaming;
44	  const onStopRef = useRef(onStop);
45	  onStopRef.current = onStop;
46	  const onFocusShortcutRef = useRef(onFocusShortcut);
47	  onFocusShortcutRef.current = onFocusShortcut;
48	
49	  // Global keyboard shortcuts: Cmd/Ctrl+K and bare "/" focus the textarea
50	  // and scroll to bottom. Skipped when an editable element already has focus
51	  // so the "/" shortcut doesn't hijack normal typing in another field.
52	  useEffect(() => {
53	    if (typeof window === "undefined") return;
54	    function isEditableTarget(t: EventTarget | null): boolean {
55	      if (!(t instanceof HTMLElement)) return false;
56	      const tag = t.tagName;
57	      if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") return true;
58	      if (t.isContentEditable) return true;
59	      return false;
60	    }
61	    function handleGlobal(e: globalThis.KeyboardEvent) {
62	      const cmdK = (e.metaKey || e.ctrlKey) && (e.key === "k" || e.key === "K");
63	      const slash = e.key === "/" && !e.metaKey && !e.ctrlKey && !e.altKey;
64	      if (!cmdK && !slash) return;
65	      if (slash && isEditableTarget(e.target)) return;
66	      e.preventDefault();
67	      const ta = textareaRef.current;
68	      if (ta) {
69	        ta.focus();
70	        try {
71	          const len = ta.value.length;
72	          ta.setSelectionRange(len, len);
73	        } catch {
74	          // ignore if browser disallows
75	        }
76	        ta.scrollIntoView({ block: "end", behavior: "smooth" });
77	      }
78	      if (onFocusShortcutRef.current) onFocusShortcutRef.current();
79	    }
80	    window.addEventListener("keydown", handleGlobal);
81	    return () => window.removeEventListener("keydown", handleGlobal);
82	  }, []);
83	
84	  useEffect(() => {
85	    const ta = textareaRef.current;
86	    if (!ta) return;
87	    ta.style.height = "auto";
88	    // Cap auto-grow at MAX_ROWS lines; beyond that the textarea scrolls.
89	    const styles = window.getComputedStyle(ta);
90	    const lineHeight = parseFloat(styles.lineHeight) || 0;
91	    const padTop = parseFloat(styles.paddingTop) || 0;
92	    const padBottom = parseFloat(styles.paddingBottom) || 0;
93	    const borderTop = parseFloat(styles.borderTopWidth) || 0;
94	    const borderBottom = parseFloat(styles.borderBottomWidth) || 0;
95	    const cap =
96	      lineHeight * MAX_ROWS + padTop + padBottom + borderTop + borderBottom;
97	    const next = Math.min(ta.scrollHeight, cap || ta.scrollHeight);
98	    ta.style.height = `${next}px`;
99	  }, [value]);
100	
101	  function handleChange(e: ChangeEvent<HTMLTextAreaElement>) {
102	    const next = e.target.value.slice(0, MAX_LEN);
103	    onChange(next);
104	  }
105	
106	  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
107	    if (e.key === "Enter" && !e.shiftKey) {
108	      e.preventDefault();
109	      if (canSubmit) onSubmit();
110	      return;
111	    }
112	    if (e.key === "Escape") {
113	      if (isStreamingRef.current && onStopRef.current) {
114	        e.preventDefault();
115	        onStopRef.current();
116	      } else {
117	        e.preventDefault();
118	        textareaRef.current?.blur();
