49	    if (!open) return;
50	    closeBtnRef.current?.focus();
51	
52	    const handleKey = (e: KeyboardEvent) => {
53	      if (e.key === "Escape") {
54	        e.preventDefault();
55	        close();
56	        return;
57	      }
58	      if (e.key !== "Tab" || !panelRef.current) return;
59	
60	      const focusables = Array.from(
61	        panelRef.current.querySelectorAll<HTMLElement>(
62	          'a[href], button:not([disabled]), [tabindex]:not([tabindex="-1"])',
63	        ),
64	      ).filter((el) => !el.hasAttribute("aria-hidden"));
65	
66	      if (focusables.length === 0) return;
67	      const first = focusables[0];
68	      const last = focusables[focusables.length - 1];
69	      const active = document.activeElement as HTMLElement | null;
