50	
51	type ServerMessage = { role: "user" | "assistant"; content: string };
52	
53	type RateLimitedBody = {
54	  error?: string;
55	  detail?: string;
56	  retryAfterSeconds?: number;
57	};
58	
59	function friendlyErrorForStatus(
60	  status: number,
61	  body: RateLimitedBody | undefined,
62	): string {
63	  if (status === 400) {
64	    return "Hmm, the request didn't validate. Try shortening your question.";
65	  }
66	  if (status === 429) {
67	    const seconds =
68	      typeof body?.retryAfterSeconds === "number" && body.retryAfterSeconds > 0
69	        ? body.retryAfterSeconds
70	        : 0;
71	    const minutes = Math.max(1, Math.ceil(seconds / 60));
72	    return `You've hit the per-hour limit (resets in ${minutes} minute${
73	      minutes === 1 ? "" : "s"
74	    }). Try again then.`;
