          </nav>

          <ThemeToggle className="shell-header__theme" />

          <button
            type="button"
            className="shell-header__hamburger"
            aria-label={open ? "Close navigation" : "Open navigation"}
            aria-expanded={open}
            aria-controls="mobile-drawer"
            onClick={toggle}
          >
            <span aria-hidden="true">☰</span>
          </button>
        </Container>
      </header>
    </>
  );
}

